const BANK_STORAGE_KEY = "family_feud_bank_v1";

/* =========================================================
   TXT IMPORT / EXPORT
   Imports populate the Question Bank (grouped by category);
   the host then picks specific questions from the bank into
   the live Rounds sequence via the category browser.
========================================================= */
const EXAMPLE_TXT = `# Family Feud question bank
# Separate each question with a blank line. Lines starting with # are ignored.
# Multiple questions can share the same category — they'll all appear
# together when you browse that category.

Category: Household
Question: Name something you always forget to bring on vacation
Phone charger - 32
Toothbrush - 26
Sunscreen - 19
Medication - 12
Swimsuit - 7
Umbrella - 4

Category: Work Life
Question: Name a reason people give for being late to work
Traffic - 35
Overslept - 24
Car trouble - 16
Kids / family emergency - 12
Lost track of time - 8
Weather - 5

Category: Food
Question: Name a topping people put on pizza that starts an argument
Pineapple - 41
Anchovies - 22
Extra cheese - 15
Mushrooms - 11
Pickles - 6
Ketchup - 5
`;

function parseBankTxt(text){
  const errors = [];
  const blocks = text.replace(/\r\n/g,"\n").split(/\n\s*\n+/).map(b=>b.trim()).filter(Boolean);
  const bank = {};
  blocks.forEach((block, bi) => {
    const rawLines = block.split("\n").map(l=>l.trim()).filter(l => l && !l.startsWith("#"));
    if(rawLines.length < 3){
      errors.push(`Block ${bi+1}: needs a category line, a question line, and at least one answer — skipped.`);
      return;
    }
    let idx = 0;
    let category = rawLines[idx];
    const catMatch = category.match(/^category\s*:\s*(.*)$/i);
    if(catMatch) category = catMatch[1].trim();
    idx++;
    let question = rawLines[idx];
    const qMatch = question.match(/^question\s*:\s*(.*)$/i);
    if(qMatch) question = qMatch[1].trim();
    idx++;
    const answers = [];
    for(; idx < rawLines.length; idx++){
      const line = rawLines[idx];
      let m = line.match(/^(.+?)\s*[-–—]\s*(\d+)\s*$/);
      if(!m) m = line.match(/^(.+?)\s*,\s*(\d+)\s*$/);
      if(!m) m = line.match(/^(.+?)\s+(\d+)\s*$/);
      if(m){
        answers.push({text: m[1].trim(), points: parseInt(m[2],10)});
      } else {
        errors.push(`Block ${bi+1}, line "${line}": couldn't find a point value at the end — skipped.`);
      }
    }
    if(!category || !question || answers.length === 0){
      errors.push(`Block ${bi+1}: missing category, question, or any valid answers — whole question skipped.`);
      return;
    }
    if(!bank[category]) bank[category] = [];
    bank[category].push({question, answers});
  });
  return {bank, errors};
}

function bankToTxt(bank){
  const blocks = [];
  Object.keys(bank).forEach(cat => {
    bank[cat].forEach(q => {
      blocks.push(`Category: ${cat}\nQuestion: ${q.question}\n` + q.answers.map(a=>`${a.text} - ${a.points}`).join("\n"));
    });
  });
  return blocks.join("\n\n") + "\n";
}

function downloadTextFile(filename, text){
  const blob = new Blob([text], {type:"text/plain"});
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url; a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  setTimeout(()=>URL.revokeObjectURL(url), 1000);
}

