/* =========================================================
   AUDIO
========================================================= */
let audioCtx = null;
function playTone(freq, duration, type, delay = 0){
  try{
    audioCtx = audioCtx || new (window.AudioContext || window.webkitAudioContext)();
    const osc = audioCtx.createOscillator();
    const gain = audioCtx.createGain();
    osc.type = type; osc.frequency.value = freq;
    osc.connect(gain); gain.connect(audioCtx.destination);
    const t0 = audioCtx.currentTime + delay;
    gain.gain.setValueAtTime(0.0001, t0);
    gain.gain.exponentialRampToValueAtTime(0.3, t0 + 0.02);
    gain.gain.exponentialRampToValueAtTime(0.0001, t0 + duration);
    osc.start(t0); osc.stop(t0 + duration + 0.05);
  }catch(e){}
}
function sfxDing(){ playTone(880,0.15,"sine"); playTone(1174,0.2,"sine",0.09); }
function sfxBuzz(){ playTone(140,0.5,"sawtooth"); }
function sfxAward(){ [523,659,784,1046].forEach((f,i)=>playTone(f,0.22,"triangle",i*0.1)); }
function sfxTimeUp(){ [1046,1046,1046].forEach((f,i)=>playTone(f,0.13,"square",i*0.22)); }

/* =========================================================
   AUDIENCE DOCUMENT BUILD + RENDER
========================================================= */
function buildAudienceDocument(doc){
  doc.open();
  doc.write(`<!DOCTYPE html><html><head><meta charset="utf-8"><title>Family Feud — Audience Display</title>
    <style>${AUDIENCE_CSS}</style></head><body>${AUDIENCE_BODY}</body></html>`);
  doc.close();
  placeBulbs(doc);

  // Recalculate bulb positions on resize/fullscreen — otherwise they stay
  // clustered at their original (small) size while the CSS border scales
  // up, making the lit outline look like a static square in the middle.
  const win = doc.defaultView;
  let resizeTimer = null;
  const recalc = () => { clearTimeout(resizeTimer); resizeTimer = win.setTimeout(() => placeBulbs(doc), 100); };
  win.addEventListener("resize", recalc);
  doc.addEventListener("fullscreenchange", recalc);
  doc.addEventListener("webkitfullscreenchange", recalc);
}

function placeBulbs(doc){
  const container = doc.getElementById("bulbs");
  if(!container) return;
  container.innerHTML = "";
  const w = (doc.documentElement.clientWidth || doc.defaultView.innerWidth || 1280) - 28;
  const h = (doc.documentElement.clientHeight || doc.defaultView.innerHeight || 720) - 28;
  const perim = 2*w + 2*h;
  const n = 60;
  for(let i=0;i<n;i++){
    const b = doc.createElement("div");
    b.className = "bulb";
    const t = i / n;
    const d = t * perim;
    let x, y;
    if(d < w){ x = 14+d; y = 14; }
    else if(d < w+h){ x = 14+w; y = 14+(d-w); }
    else if(d < 2*w+h){ x = 14+w-(d-w-h); y = 14+h; }
    else { x = 14; y = 14+h-(d-2*w-h); }
    b.style.left = x+"px"; b.style.top = y+"px";
    b.style.animationDelay = (t*1.6)+"s";
    container.appendChild(b);
  }
}

function spawnConfetti(doc){
  const colors = ["#E8B94A","#FFD966","#E63946","#3DDC84","#F5EFE0"];
  for(let i=0;i<60;i++){
    const c = doc.createElement("div");
    c.className = "confetti";
    c.style.left = Math.random()*100+"vw";
    c.style.background = colors[Math.floor(Math.random()*colors.length)];
    c.style.animationDuration = (2+Math.random()*1.5)+"s";
    c.style.animationDelay = (Math.random()*0.6)+"s";
    doc.body.appendChild(c);
    setTimeout(()=>c.remove(), 4000);
  }
}

// remember previous values per-target so we can detect *new* reveals/score changes to animate
let prevSnapshot = { preview: null, popup: null };
let lastEventPlayedId = { preview: null, popup: null };

function animateNumber(doc, el, from, to, duration){
  from = Number.isFinite(from) ? from : to;
  if(from === to){ el.textContent = to; el._animToken = null; return; }
  const win = doc.defaultView;
  const start = win.performance.now();
  const token = Symbol();
  el._animToken = token;
  function tick(now){
    if(el._animToken !== token) return; // superseded by a newer animation
    const p = Math.max(0, Math.min(1, (now - start) / duration));
    const eased = 1 - Math.pow(1-p, 3);
    el.textContent = Math.round(from + (to-from)*eased);
    if(p < 1) win.requestAnimationFrame(tick);
    else { el.textContent = to; el._animToken = null; }
  }
  win.requestAnimationFrame(tick);
}

function renderBoardOnDoc(doc, state, key){
  const r = state.rounds[state.currentRoundIndex];
  document.getElementById && null; // no-op guard
  const catEl = doc.getElementById("audCategory");
  const qEl = doc.getElementById("audQuestion");
  catEl.textContent = r.category;
  qEl.textContent = r.question;

  const board = doc.getElementById("audAnswerBoard");
  const prev = prevSnapshot[key];
  const prevRound = prev && prev.rounds ? prev.rounds[prev.currentRoundIndex] : null;
  const sameQuestion = prevRound && prevRound.question === r.question;

  board.innerHTML = "";
  r.answers.forEach((a,i) => {
    const wasRevealed = sameQuestion && prevRound.answers[i] && prevRound.answers[i].revealed;
    const slot = doc.createElement("div");
    slot.className = "answer-slot" + (a.revealed ? " revealed" : "") + (a.revealed && !wasRevealed ? " justRevealed" : "") + (!sameQuestion ? " slotIn" : "");
    if(!sameQuestion) slot.style.animationDelay = (i*0.07)+"s";
    slot.innerHTML = `
      <div class="slot-inner">
        <div class="slot-face slot-back"><span class="slot-number">${i+1}</span><span></span></div>
        <div class="slot-face slot-front"><span class="ans-text">${a.text}</span><span class="ans-pts">${a.points}</span></div>
      </div>
    `;
    board.appendChild(slot);
  });

  doc.getElementById("audTeam1Name").textContent = state.team1.name;
  doc.getElementById("audTeam2Name").textContent = state.team2.name;

  const t1ScoreEl = doc.getElementById("audTeam1Score");
  const t2ScoreEl = doc.getElementById("audTeam2Score");
  const prevT1 = prev ? prev.team1.score : state.team1.score;
  const prevT2 = prev ? prev.team2.score : state.team2.score;
  animateNumber(doc, t1ScoreEl, prevT1, state.team1.score, 500);
  animateNumber(doc, t2ScoreEl, prevT2, state.team2.score, 500);
  if(prev && prevT1 !== state.team1.score){
    const c = doc.getElementById("audTeam1Card"); c.classList.remove("bump"); void c.offsetWidth; c.classList.add("bump");
  }
  if(prev && prevT2 !== state.team2.score){
    const c = doc.getElementById("audTeam2Card"); c.classList.remove("bump"); void c.offsetWidth; c.classList.add("bump");
  }

  const potEl = doc.getElementById("audPot");
  const prevPot = prev ? prev.pot : state.pot;
  animateNumber(doc, potEl, prevPot, state.pot, 400);

  const strikes = doc.getElementById("audStrikes");
  strikes.innerHTML = "";
  for(let i=0;i<state.strikeLimit;i++){
    const box = doc.createElement("div");
    box.className = "strike-box" + (i < r.strikes ? " active" : "");
    box.textContent = "✕";
    strikes.appendChild(box);
  }
}

function flashStrikeOnDoc(doc){
  const el = doc.getElementById("strikeFlash");
  el.classList.remove("show");
  void el.offsetWidth;
  el.classList.add("show");
  setTimeout(()=>el.classList.remove("show"), 600);
}

function flashRepeatOnDoc(doc){
  const el = doc.getElementById("repeatFlash");
  el.classList.remove("show");
  void el.offsetWidth;
  el.classList.add("show");
  setTimeout(()=>el.classList.remove("show"), 800);
}

function formatTime(seconds){
  seconds = Math.max(0, Math.ceil(seconds));
  const m = Math.floor(seconds/60);
  const s = seconds % 60;
  return m + ":" + String(s).padStart(2,"0");
}

const TIMER_CIRCUMFERENCE = 2 * Math.PI * 44;

function updateTimerOnDoc(doc, state){
  const widget = doc.getElementById("timerWidget");
  const ring = doc.getElementById("timerRingFg");
  const num = doc.getElementById("timerNum");
  if(!widget || !ring || !num) return;
  const duration = Math.max(1, state.timer.duration);
  const remaining = Math.max(0, state.timer.remaining);
  const frac = Math.min(1, remaining / duration);
  ring.style.strokeDasharray = TIMER_CIRCUMFERENCE;
  ring.style.strokeDashoffset = TIMER_CIRCUMFERENCE * (1 - frac);
  num.textContent = formatTime(remaining);
  const armed = state.timer.running || remaining < duration;
  widget.classList.toggle("armed", armed);
  widget.classList.toggle("warning", state.timer.running && remaining <= 10 && remaining > 0);
}

function flashTimerDoneOnDoc(doc){
  const widget = doc.getElementById("timerWidget");
  if(!widget) return;
  widget.classList.remove("done");
  void widget.offsetWidth;
  widget.classList.add("done");
  setTimeout(()=>widget.classList.remove("done"), 2200);
}

function renderIntroOnDoc(doc, state){
  const t1 = doc.getElementById("introTeam1");
  const t2 = doc.getElementById("introTeam2");
  if(t1) t1.textContent = state.team1.name;
  if(t2) t2.textContent = state.team2.name;
}

function replayIntroOnDoc(doc){
  const els = doc.querySelectorAll(".intro-logo-img, .intro-vs, .intro-tagline");
  els.forEach(el => {
    el.style.animation = "none";
    void el.offsetWidth;
    el.style.animation = "";
  });
}

let prevScreen = { preview: null, popup: null };

function renderAudienceOnDoc(doc, state, key){
  const screenIntro = doc.getElementById("screenIntro");
  const screenBoard = doc.getElementById("screenBoard");
  if(!screenIntro || !screenBoard) return;

  const target = state.introActive ? "intro" : "board";
  screenIntro.classList.toggle("active", target === "intro");
  screenBoard.classList.toggle("active", target === "board");

  renderIntroOnDoc(doc, state);
  if(target === "board") renderBoardOnDoc(doc, state, key);
  updateTimerOnDoc(doc, state);

  if(target === "intro" && prevScreen[key] !== "intro"){
    replayIntroOnDoc(doc);
  }
  prevScreen[key] = target;

  if(state.lastEvent && state.lastEvent.id !== lastEventPlayedId[key]){
    lastEventPlayedId[key] = state.lastEvent.id;
    const t = state.lastEvent.type;
    if(t === "reveal") sfxDing();
    else if(t === "strike"){ sfxBuzz(); flashStrikeOnDoc(doc); }
    else if(t === "award") { sfxAward(); spawnConfetti(doc); }
    else if(t === "repeat"){ sfxBuzz(); flashRepeatOnDoc(doc); }
    else if(t === "timerEnd"){ sfxTimeUp(); flashTimerDoneOnDoc(doc); }
  }

  prevSnapshot[key] = JSON.parse(JSON.stringify(state));
}

/* =========================================================
   RENDER TARGET REGISTRY
========================================================= */
const previewFrame = document.getElementById("previewFrame");
let popupWin = null;

function renderAllAudience(state){
  try{
    if(previewFrame && previewFrame.contentDocument){
      renderAudienceOnDoc(previewFrame.contentDocument, state, "preview");
    }
  }catch(e){}
  try{
    if(popupWin && !popupWin.closed){
      renderAudienceOnDoc(popupWin.document, state, "popup");
    }
  }catch(e){}
}

/* =========================================================
   GAME STATE + HOST LOGIC
========================================================= */
function loadBank(){
  try{
    const raw = localStorage.getItem(BANK_STORAGE_KEY);
    if(raw) return JSON.parse(raw);
  }catch(e){}
  return JSON.parse(JSON.stringify(DEFAULT_BANK));
}
function saveBank(){
  try{ localStorage.setItem(BANK_STORAGE_KEY, JSON.stringify(state.bank)); }catch(e){}
}

let state = {
  rounds: JSON.parse(JSON.stringify(DEFAULT_ROUNDS)).map(r => ({...r, answers: r.answers.map(a => ({...a, revealed:false})), strikes:0, awardedPoints:0})),
  currentRoundIndex: 0,
  bank: loadBank(),
  strikeLimit: 3,
  team1: {name:"Team 1", score:0},
  team2: {name:"Team 2", score:0},
  pot: 0,
  introActive: true,
  timer: { duration: 30, remaining: 30, running: false, startedAt: null },
  lastEvent: null
};

function currentRound(){ return state.rounds[state.currentRoundIndex]; }

function recalcPot(){
  const total = currentRound().answers.filter(a=>a.revealed).reduce((s,a)=>s+a.points,0);
  state.pot = Math.max(0, total - (currentRound().awardedPoints || 0));
}

function selectRound(i){
  state.currentRoundIndex = i;
  recalcPot();
  renderHost(); renderAllAudience(state);
}
function addRound(){
  state.rounds.push({category:"New Category", question:"New question?", answers:[
    {text:"Answer 1", points:10, revealed:false}
  ], strikes:0, awardedPoints:0});
  state.currentRoundIndex = state.rounds.length-1;
  renderHost(); renderAllAudience(state);
}
function deleteRound(){
  if(state.rounds.length <= 1) return;
  state.rounds.splice(state.currentRoundIndex,1);
  state.currentRoundIndex = Math.max(0, state.currentRoundIndex-1);
  recalcPot();
  renderHost(); renderAllAudience(state);
}
function addQuestionFromBank(category, bq){
  state.rounds.push({
    category,
    question: bq.question,
    answers: bq.answers.map(a => ({text:a.text, points:a.points, revealed:false})),
    strikes: 0,
    awardedPoints: 0
  });
  state.currentRoundIndex = state.rounds.length - 1;
  recalcPot();
  renderHost(); renderAllAudience(state);
}
function addBankCategory(name){
  name = name.trim();
  if(!name) return;
  if(!state.bank[name]) state.bank[name] = [];
  saveBank();
  renderHost();
}
function deleteBankCategory(name){
  delete state.bank[name];
  saveBank();
  renderHost();
}
function deleteBankQuestion(category, idx){
  state.bank[category].splice(idx,1);
  if(state.bank[category].length === 0) delete state.bank[category];
  saveBank();
  renderHost();
}
function toggleReveal(i){
  const ans = currentRound().answers[i];
  ans.revealed = !ans.revealed;
  recalcPot();
  state.lastEvent = {type: ans.revealed ? "reveal" : "unreveal", id: Date.now()};
  renderHost(); renderAllAudience(state);
}
function addStrike(){
  if(currentRound().strikes >= state.strikeLimit) return;
  currentRound().strikes++;
  state.lastEvent = {type:"strike", id: Date.now()};
  renderHost(); renderAllAudience(state);
}
function markRepeat(){
  state.lastEvent = {type:"repeat", id: Date.now()};
  renderHost(); renderAllAudience(state);
}
function clearStrikes(){
  currentRound().strikes = 0;
  renderHost(); renderAllAudience(state);
}
function awardPot(teamKey){
  const amount = state.pot;
  state[teamKey].score += amount;
  currentRound().awardedPoints = (currentRound().awardedPoints || 0) + amount;
  recalcPot();
  state.lastEvent = {type:"award", id: Date.now(), team: teamKey};
  renderHost(); renderAllAudience(state);
}
function adjustScore(teamKey, delta){
  state[teamKey].score = Math.max(0, state[teamKey].score + delta);
  renderHost(); renderAllAudience(state);
}
function nextQuestion(){
  if(state.currentRoundIndex < state.rounds.length-1){
    state.currentRoundIndex++;
  } else {
    addRound();
    return;
  }
  recalcPot();
  state.lastEvent = {type:"nextQuestion", id: Date.now()};
  renderHost(); renderAllAudience(state);
}
function resetRound(){
  currentRound().answers.forEach(a=>a.revealed=false);
  currentRound().strikes = 0;
  currentRound().awardedPoints = 0;
  recalcPot();
  state.lastEvent = {type:"resetRound", id: Date.now()};
  renderHost(); renderAllAudience(state);
}
function resetGame(){
  state.rounds.forEach(r => { r.answers.forEach(a=>a.revealed=false); r.strikes=0; r.awardedPoints=0; });
  state.currentRoundIndex = 0;
  state.team1.score = 0; state.team2.score = 0;
  state.introActive = true;
  recalcPot();
  state.lastEvent = {type:"resetGame", id: Date.now()};
  renderHost(); renderAllAudience(state);
}
function startGame(){
  state.introActive = false;
  state.lastEvent = {type:"startGame", id: Date.now()};
  renderHost(); renderAllAudience(state);
}
function showIntro(){
  state.introActive = true;
  state.lastEvent = {type:"showIntro", id: Date.now()};
  renderHost(); renderAllAudience(state);
}

/* ---------- Timer ---------- */
function startOrResumeTimer(){
  if(state.timer.running) return;
  if(state.timer.remaining <= 0) state.timer.remaining = state.timer.duration;
  state.timer.startedAt = Date.now() - ((state.timer.duration - state.timer.remaining) * 1000);
  state.timer.running = true;
  renderHost(); renderAllAudience(state);
}
function pauseTimer(){
  if(!state.timer.running) return;
  const elapsed = (Date.now() - state.timer.startedAt) / 1000;
  state.timer.remaining = Math.max(0, state.timer.duration - elapsed);
  state.timer.running = false;
  renderHost(); renderAllAudience(state);
}
function resetTimer(){
  state.timer.running = false;
  state.timer.remaining = state.timer.duration;
  state.timer.startedAt = null;
  renderHost(); renderAllAudience(state);
}
function setTimerDuration(sec){
  sec = Math.max(5, Math.min(600, sec || 30));
  state.timer.duration = sec;
  if(!state.timer.running) state.timer.remaining = sec;
  renderHost(); renderAllAudience(state);
}
function timerTick(){
  if(state.timer.running){
    const elapsed = (Date.now() - state.timer.startedAt) / 1000;
    const remaining = state.timer.duration - elapsed;
    if(remaining <= 0){
      state.timer.running = false;
      state.timer.remaining = 0;
      state.lastEvent = {type:"timerEnd", id: Date.now()};
      renderHost(); renderAllAudience(state);
      return;
    }
    state.timer.remaining = remaining;
  }
  renderHostTimerReadout();
  try{ if(previewFrame && previewFrame.contentDocument) updateTimerOnDoc(previewFrame.contentDocument, state); }catch(e){}
  try{ if(popupWin && !popupWin.closed) updateTimerOnDoc(popupWin.document, state); }catch(e){}
}
function renderHostTimerReadout(){
  const el = document.getElementById("hostTimerReadout");
  if(el) el.textContent = formatTime(state.timer.remaining);
  const startBtn = document.getElementById("btnTimerStart");
  const pauseBtn = document.getElementById("btnTimerPause");
  if(startBtn) startBtn.disabled = state.timer.running;
  if(pauseBtn) pauseBtn.disabled = !state.timer.running;
  const durInput = document.getElementById("timerDurationInput");
  if(durInput) durInput.disabled = state.timer.running;
}

/* ---------- host rendering ---------- */
let bankDraft = { category: "", question: "", answers: [{text:"",points:""}] };

function renderQuestionBank(){
  const el = document.getElementById("bankBrowser");
  el.innerHTML = "";
  const cats = Object.keys(state.bank);
  if(cats.length === 0){
    el.innerHTML = `<div class="hint">No questions in the bank yet — import a .txt file or add one below.</div>`;
  }
  cats.forEach(cat => {
    const block = document.createElement("div");
    block.className = "bank-category-block";
    const title = document.createElement("div");
    title.className = "category-title";
    title.innerHTML = `<span>${cat}</span> <button class="bank-del-cat" data-cat="${cat}" title="Delete category">✕</button>`;
    block.appendChild(title);
    const list = document.createElement("div");
    list.className = "bank-question-list";
    state.bank[cat].forEach((bq, qi) => {
      const row = document.createElement("div");
      row.className = "bank-question-row";
      const totalPts = bq.answers.reduce((s,a)=>s+a.points,0);
      row.innerHTML = `
        <button class="bank-question-pick" data-cat="${cat}" data-idx="${qi}">
          <span class="bq-text">${bq.question}</span>
          <span class="bq-meta">${bq.answers.length} answers · ${totalPts} pts</span>
        </button>
        <button class="bank-del-q" data-cat="${cat}" data-idx="${qi}" title="Delete from bank">✕</button>
      `;
      list.appendChild(row);
    });
    block.appendChild(list);
    el.appendChild(block);
  });

  el.querySelectorAll(".bank-question-pick").forEach(btn => btn.onclick = (e) => {
    const cat = btn.dataset.cat;
    const idx = +btn.dataset.idx;
    addQuestionFromBank(cat, state.bank[cat][idx]);
  });
  el.querySelectorAll(".bank-del-q").forEach(btn => btn.onclick = (e) => {
    e.stopPropagation();
    deleteBankQuestion(btn.dataset.cat, +btn.dataset.idx);
  });
  el.querySelectorAll(".bank-del-cat").forEach(btn => btn.onclick = (e) => {
    e.stopPropagation();
    deleteBankCategory(btn.dataset.cat);
  });

  renderBankDraft();
}

function renderBankDraft(){
  document.getElementById("draftQuestion").value = bankDraft.question;
  document.getElementById("draftCategory").value = bankDraft.category;
  const catList = document.getElementById("draftCategoryList");
  catList.innerHTML = Object.keys(state.bank).map(c => `<option value="${c}">`).join("");

  const list = document.getElementById("draftAnswerList");
  list.innerHTML = "";
  bankDraft.answers.forEach((a, i) => {
    const row = document.createElement("div");
    row.className = "answer-edit-row";
    row.innerHTML = `
      <input type="text" class="draft-ans-text" placeholder="Answer" value="${(a.text||"").replace(/"/g,'&quot;')}" data-idx="${i}">
      <input type="number" class="draft-ans-pts" placeholder="Pts" value="${a.points||""}" data-idx="${i}">
      <button data-idx="${i}" title="Remove row">✕</button>
    `;
    list.appendChild(row);
  });
  list.querySelectorAll(".draft-ans-text").forEach(inp => inp.oninput = e => {
    bankDraft.answers[+e.target.dataset.idx].text = e.target.value;
  });
  list.querySelectorAll(".draft-ans-pts").forEach(inp => inp.oninput = e => {
    bankDraft.answers[+e.target.dataset.idx].points = parseInt(e.target.value,10) || 0;
  });
  list.querySelectorAll("button").forEach(btn => btn.onclick = e => {
    bankDraft.answers.splice(+e.target.dataset.idx,1);
    if(bankDraft.answers.length === 0) bankDraft.answers.push({text:"",points:""});
    renderBankDraft();
  });
}

function renderRoundTabs(){
  const el = document.getElementById("roundTabs");
  el.innerHTML = "";
  state.rounds.forEach((r,i) => {
    const tab = document.createElement("button");
    tab.className = "round-tab" + (i===state.currentRoundIndex ? " active" : "");
    tab.textContent = "Q" + (i+1);
    tab.onclick = () => selectRound(i);
    el.appendChild(tab);
  });
  document.getElementById("roundCountHint").textContent = state.rounds.length + " round" + (state.rounds.length===1?"":"s");
}

function renderEditor(){
  const r = currentRound();
  document.getElementById("editCategory").value = r.category;
  document.getElementById("editQuestion").value = r.question;
  const list = document.getElementById("answerEditList");
  list.innerHTML = "";
  r.answers.forEach((a, i) => {
    const row = document.createElement("div");
    row.className = "answer-edit-row";
    row.innerHTML = `
      <input type="text" class="ans-text" value="${a.text.replace(/"/g,'&quot;')}" data-idx="${i}">
      <input type="number" class="ans-pts" value="${a.points}" data-idx="${i}">
      <button data-idx="${i}" title="Delete answer">✕</button>
    `;
    list.appendChild(row);
  });
  list.querySelectorAll(".ans-text").forEach(inp => inp.onchange = (e) => {
    r.answers[+e.target.dataset.idx].text = e.target.value;
    renderHost(); renderAllAudience(state);
  });
  list.querySelectorAll(".ans-pts").forEach(inp => inp.onchange = (e) => {
    r.answers[+e.target.dataset.idx].points = parseInt(e.target.value,10) || 0;
    recalcPot();
    renderHost(); renderAllAudience(state);
  });
  list.querySelectorAll("button").forEach(btn => btn.onclick = (e) => {
    r.answers.splice(+e.target.dataset.idx,1);
    recalcPot();
    renderHost(); renderAllAudience(state);
  });
}

function renderBoardControl(){
  const r = currentRound();
  const el = document.getElementById("boardControlList");
  el.innerHTML = "";
  r.answers.forEach((a,i) => {
    const row = document.createElement("div");
    row.className = "board-row" + (a.revealed ? " revealed" : "");
    row.innerHTML = `
      <div class="ans-info"><span class="rank">${i+1}</span><span>${a.text}</span></div>
      <div style="display:flex;align-items:center;gap:10px;">
        <span class="pts">${a.points} pts</span>
      </div>
    `;
    const btn = document.createElement("button");
    btn.className = "btn btn-sm " + (a.revealed ? "btn-outline" : "btn-gold");
    btn.textContent = a.revealed ? "Hide" : "Reveal";
    btn.onclick = () => toggleReveal(i);
    row.querySelector("div:last-child").appendChild(btn);
    el.appendChild(row);
  });
  document.getElementById("potValue").textContent = state.pot;
}

function renderScores(){
  document.getElementById("team1Name").value = state.team1.name;
  document.getElementById("team2Name").value = state.team2.name;
  document.getElementById("team1Score").textContent = state.team1.score;
  document.getElementById("team2Score").textContent = state.team2.score;
  const sb = document.getElementById("strikeBoxes");
  sb.innerHTML = "";
  for(let i=0;i<state.strikeLimit;i++){
    const box = document.createElement("div");
    box.className = "strike-x" + (i < currentRound().strikes ? " active" : "");
    box.textContent = "✕";
    sb.appendChild(box);
  }
}

function renderHost(){
  renderQuestionBank();
  renderRoundTabs();
  renderEditor();
  renderBoardControl();
  renderScores();
  renderHostTimerReadout();
  document.getElementById("strikeLimitInput").value = state.strikeLimit;
}

/* =========================================================
   INIT + WIRING
========================================================= */
function setConn(ok){
  const pill = document.getElementById("connStatus");
  const txt = document.getElementById("connText");
  pill.classList.toggle("connected", ok);
  txt.textContent = ok ? "Second screen connected" : "Second screen not launched";
}

function init(){
  renderHost();
  buildAudienceDocument(previewFrame.contentDocument);
  renderAllAudience(state);
  setInterval(timerTick, 200);

  document.getElementById("btnLaunch").onclick = () => {
    if(popupWin && !popupWin.closed){
      popupWin.focus();
      return;
    }
    popupWin = window.open("", "feudAudience", "width=1280,height=720,menubar=no,toolbar=no,location=no,status=no");
    if(!popupWin){
      alert("Your browser blocked the popup. Please allow popups for this page and click Launch again.");
      return;
    }
    buildAudienceDocument(popupWin.document);
    renderAllAudience(state);
    setConn(true);
    const poll = setInterval(() => {
      if(!popupWin || popupWin.closed){ setConn(false); popupWin = null; clearInterval(poll); }
    }, 800);
  };

  document.getElementById("btnPreviewFullscreen").onclick = () => {
    if(previewFrame.requestFullscreen) previewFrame.requestFullscreen();
    else if(previewFrame.webkitRequestFullscreen) previewFrame.webkitRequestFullscreen();
  };

  document.getElementById("btnAddRound").onclick = addRound;
  document.getElementById("btnDeleteRound").onclick = deleteRound;
  document.getElementById("editCategory").onchange = e => { currentRound().category = e.target.value; renderAllAudience(state); };
  document.getElementById("editQuestion").onchange = e => { currentRound().question = e.target.value; renderAllAudience(state); };
  document.getElementById("btnAddAnswer").onclick = () => {
    currentRound().answers.push({text:"New answer", points:5, revealed:false});
    renderHost(); renderAllAudience(state);
  };
  document.getElementById("strikeLimitInput").onchange = e => {
    let v = parseInt(e.target.value,10);
    if(isNaN(v)||v<1) v=1; if(v>5) v=5;
    state.strikeLimit = v; e.target.value = v;
    renderHost(); renderAllAudience(state);
  };
  document.getElementById("team1Name").onchange = e => { state.team1.name = e.target.value || "Team 1"; renderAllAudience(state); };
  document.getElementById("team2Name").onchange = e => { state.team2.name = e.target.value || "Team 2"; renderAllAudience(state); };
  document.getElementById("btnAwardTeam1").onclick = () => awardPot("team1");
  document.getElementById("btnAwardTeam2").onclick = () => awardPot("team2");
  document.getElementById("btnMinus1").onclick = () => adjustScore("team1", -10);
  document.getElementById("btnMinus2").onclick = () => adjustScore("team2", -10);
  document.getElementById("btnAddStrike").onclick = addStrike;
  document.getElementById("btnRepeatAnswer").onclick = markRepeat;
  document.getElementById("btnClearStrikes").onclick = clearStrikes;
  document.getElementById("btnNextQuestion").onclick = nextQuestion;
  document.getElementById("btnResetRound").onclick = resetRound;
  document.getElementById("btnResetGame").onclick = resetGame;

  document.getElementById("btnStartGame").onclick = startGame;
  document.getElementById("btnShowIntro").onclick = showIntro;

  document.getElementById("btnTimerStart").onclick = startOrResumeTimer;
  document.getElementById("btnTimerPause").onclick = pauseTimer;
  document.getElementById("btnTimerReset").onclick = resetTimer;
  document.getElementById("timerDurationInput").onchange = e => {
    setTimerDuration(parseInt(e.target.value,10));
  };

  document.getElementById("btnToggleFormatHelp").onclick = () => {
    document.getElementById("formatHelpBody").classList.toggle("open");
  };
  document.getElementById("btnDownloadExample").onclick = () => {
    downloadTextFile("family-feud-questions-example.txt", EXAMPLE_TXT);
  };
  document.getElementById("btnExportTxt").onclick = () => {
    downloadTextFile("family-feud-bank.txt", bankToTxt(state.bank));
  };

  document.getElementById("btnDraftAddAnswer").onclick = () => {
    bankDraft.answers.push({text:"",points:""});
    renderBankDraft();
  };
  document.getElementById("btnDraftSave").onclick = () => {
    const category = document.getElementById("draftCategory").value.trim();
    const question = document.getElementById("draftQuestion").value.trim();
    const answers = bankDraft.answers
      .map(a => ({text:(a.text||"").trim(), points: a.points||0}))
      .filter(a => a.text);
    if(!category || !question || answers.length === 0){
      alert("Please fill in a category, a question, and at least one answer with points before saving.");
      return;
    }
    if(!state.bank[category]) state.bank[category] = [];
    state.bank[category].push({question, answers});
    saveBank();
    bankDraft = { category, question: "", answers: [{text:"",points:""}] };
    renderHost();
  };

  let pendingImport = null;
  const importModal = document.getElementById("importModal");
  const txtInput = document.getElementById("txtImportInput");

  txtInput.onchange = (e) => {
    const file = e.target.files[0];
    if(!file) return;
    const reader = new FileReader();
    reader.onload = () => {
      const { bank, errors } = parseBankTxt(String(reader.result));
      pendingImport = bank;
      const cats = Object.keys(bank);
      const totalQuestions = cats.reduce((s,c)=>s+bank[c].length,0);
      const summary = document.getElementById("importSummary");
      const errBox = document.getElementById("importErrors");
      if(cats.length === 0){
        summary.textContent = "No valid questions could be read from this file — nothing to import.";
        document.getElementById("btnImportReplace").disabled = true;
        document.getElementById("btnImportAdd").disabled = true;
      } else {
        summary.textContent = `Found ${totalQuestions} question${totalQuestions===1?"":"s"} across ${cats.length} categor${cats.length===1?"y":"ies"}. What would you like to do?`;
        document.getElementById("btnImportReplace").disabled = false;
        document.getElementById("btnImportAdd").disabled = false;
      }
      errBox.innerHTML = errors.length ? ("⚠ " + errors.join("<br>⚠ ")) : "";
      importModal.classList.add("show");
    };
    reader.readAsText(file);
    txtInput.value = "";
  };

  document.getElementById("btnImportReplace").onclick = () => {
    if(!pendingImport || !Object.keys(pendingImport).length) return;
    state.bank = pendingImport;
    saveBank();
    importModal.classList.remove("show");
    renderHost();
  };
  document.getElementById("btnImportAdd").onclick = () => {
    if(!pendingImport || !Object.keys(pendingImport).length) return;
    Object.keys(pendingImport).forEach(cat => {
      state.bank[cat] = (state.bank[cat] || []).concat(pendingImport[cat]);
    });
    saveBank();
    importModal.classList.remove("show");
    renderHost();
  };
  document.getElementById("btnImportCancel").onclick = () => {
    importModal.classList.remove("show");
  };
}

if(document.readyState === "loading"){
  document.addEventListener("DOMContentLoaded", init);
} else {
  init();
}
